import org.apache.nifi.processor.io.StreamCallback
import java.nio.charset.StandardCharsets
import groovy.json.JsonOutput

def flowFile = session.get()
if (!flowFile) return

def random = new Random()

def firstNames = ['John','Jane','Alice','Bob','Charlie','Emma','Liam','Olivia','Noah','Sophia',
                  'James','Mary','Robert','Patricia','Michael','Jennifer','William','Linda','David','Elizabeth']
def lastNames = ['Smith','Jones','Brown','Wilson','Taylor','Davis','Clark','Moore','White','Harris',
                 'Martin','Garcia','Martinez','Robinson','Lewis','Walker','Hall','Allen','Young','King']
def statuses = ['pending','processing','shipped','delivered','cancelled']
def products = ['Laptop','Mouse','Keyboard','Monitor','Headphones','USB Cable','Webcam','Desk Lamp',
                'Chair','Backpack','Tablet','Phone Case','SSD Drive','RAM Module','Power Bank']
def addresses = ['123 Main St, New York, NY','456 Oak Ave, Los Angeles, CA','789 Pine Rd, Chicago, IL',
                 '321 Elm St, Houston, TX','654 Maple Dr, Phoenix, AZ','987 Cedar Ln, Philadelphia, PA']

def pick = { list -> list[random.nextInt(list.size())] }
def now = System.currentTimeMillis()

def createFF = { content, attrs ->
    def ff = session.create(flowFile)
    ff = session.write(ff, { inputStream, outputStream ->
        outputStream.write(JsonOutput.toJson(content).getBytes(StandardCharsets.UTF_8))
    } as StreamCallback)
    ff = session.putAttribute(ff, 'mime.type', 'application/json')
    attrs.each { k, v -> ff = session.putAttribute(ff, k, v) }
    session.transfer(ff, REL_SUCCESS)
}

def customerIds = (1..5).collect { random.nextInt(200) + 1 }
def customers = customerIds.collect { id ->
    [customer_id: id, first_name: pick(firstNames), last_name: pick(lastNames),
     email: "user_${id}@example.com", phone: "+1-${random.nextInt(900)+100}-${random.nextInt(9000)+1000}",
     updated_at: now]
}
createFF(customers, [operation: 'upsert', target_table: 'customers', 'update.keys': 'customer_id', 'statement.type': 'UPSERT', priority: '1'])

def orderIds = (1..10).collect { random.nextInt(500) + 1 }
def orders = orderIds.collect { id ->
    [order_id: id, customer_id: pick(customerIds), order_status: pick(statuses),
     total_amount: (random.nextInt(99000) + 1000) / 100.0, shipping_address: pick(addresses),
     updated_at: now]
}
createFF(orders, [operation: 'upsert', target_table: 'orders', 'update.keys': 'order_id', 'statement.type': 'UPSERT', priority: '2'])

def items = (1..15).collect {
    [order_id: pick(orderIds), product_name: pick(products),
     quantity: random.nextInt(5) + 1, unit_price: (random.nextInt(49500) + 500) / 100.0]
}
createFF(items, [operation: 'insert', target_table: 'order_items', 'statement.type': 'INSERT', priority: '3', 'update.keys': 'item_id'])

def deleteOrderId = pick(orderIds)
createFF([[order_id: deleteOrderId]],
    [operation: 'delete', target_table: 'order_items', 'update.keys': 'order_id', 'statement.type': 'DELETE', priority: '4'])
createFF([[order_id: deleteOrderId]],
    [operation: 'delete', target_table: 'orders', 'update.keys': 'order_id', 'statement.type': 'DELETE', priority: '5'])

session.remove(flowFile)
